import{_ as u,C as o,o as n,c as h,j as e,E as i,w as l,b as t,a4 as p,a3 as d,a as A}from"./chunks/framework.CS9vaShW.js";const q=JSON.parse('{"title":"A股高频行情接入链路（二）：券商如何通过双路组播把行情送入Colo","description":"梳理券商收到交易所行情后，如何通过内部分发节点、UDP组播、A/B交换网络和物理链路送达Colo服务器网卡。","frontmatter":{"title":"A股高频行情接入链路（二）：券商如何通过双路组播把行情送入Colo","category":"量化交易系统","tags":["高频交易","A股行情","UDP组播","Colo","A/B双路","低延迟网络"],"date":"2026-07-10T00:00:00.000Z","description":"梳理券商收到交易所行情后，如何通过内部分发节点、UDP组播、A/B交换网络和物理链路送达Colo服务器网卡。","wordCount":4392},"headers":[],"relativePath":"posts/a-share-market-data-infrastructure-2.md","filePath":"posts/a-share-market-data-infrastructure-2.md","lastUpdated":1784048132000}'),E={name:"posts/a-share-market-data-infrastructure-2.md"};function c(b,a,B,m,_,P){const s=o("Mermaid"),r=o("ClientOnly");return n(),h("div",null,[a[5]||(a[5]=e("p",null,"本文承接交易所到券商的上游链路，继续沿着券商内部行情总线、分发节点、UDP 组播、A/B 交换网络和物理链路，一直讲到行情以太网帧到达量化机构 Colo 服务器的网卡端口。本文仍不进入行情程序内部，不讨论用户态收包、消息合并、协议解码和订单簿构建。",-1)),i(r,null,{default:l(()=>[(n(),t(p,null,{default:l(()=>[i(s,{id:"mermaid-3",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20BA%5B%E5%88%B8%E5%95%86%E8%A1%8C%E6%83%85%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20A%5D%20--%3E%20BUS%5B%E5%86%85%E9%83%A8%E8%A1%8C%E6%83%85%E6%80%BB%E7%BA%BF%5D%0A%20%20%20%20BB%5B%E5%88%B8%E5%95%86%E8%A1%8C%E6%83%85%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20B%5D%20--%3E%20BUS%0A%20%20%20%20BUS%20--%3E%20FA%5B%E8%A1%8C%E6%83%85%E5%88%86%E5%8F%91%E8%8A%82%E7%82%B9%20A%5D%0A%20%20%20%20BUS%20--%3E%20FB%5B%E8%A1%8C%E6%83%85%E5%88%86%E5%8F%91%E8%8A%82%E7%82%B9%20B%5D%0A%20%20%20%20FA%20--%3E%20SWA%5B%E4%BA%A4%E6%8D%A2%E7%BD%91%E7%BB%9C%20A%5D%0A%20%20%20%20FB%20--%3E%20SWB%5B%E4%BA%A4%E6%8D%A2%E7%BD%91%E7%BB%9C%20B%5D%0A%20%20%20%20SWA%20--%3E%20CA%5BColo%20%E6%8E%A5%E5%85%A5%E4%BA%A4%E6%8D%A2%E6%9C%BA%20A%5D%0A%20%20%20%20SWB%20--%3E%20CB%5BColo%20%E6%8E%A5%E5%85%A5%E4%BA%A4%E6%8D%A2%E6%9C%BA%20B%5D%0A%20%20%20%20CA%20--%3E%20NICA%5B%E6%9C%8D%E5%8A%A1%E5%99%A8%E7%BD%91%E5%8D%A1%20A%5D%0A%20%20%20%20CB%20--%3E%20NICB%5B%E6%9C%8D%E5%8A%A1%E5%99%A8%E7%BD%91%E5%8D%A1%20B%5D%0A"})]),fallback:l(()=>[...a[0]||(a[0]=[e("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[6]||(a[6]=d(`<blockquote><p>本篇范围：券商行情接入节点的输出，直到服务器物理网卡收到以太网帧。网卡 RX Queue、内核旁路、Channel/Seq 合并、补包、解码和订单簿处理留到后续文章。</p></blockquote><h2 id="_1-券商为什么还要重新分发行情" tabindex="-1">1. 券商为什么还要重新分发行情 <a class="header-anchor" href="#_1-券商为什么还要重新分发行情" aria-label="Permalink to &quot;1. 券商为什么还要重新分发行情&quot;">​</a></h2><p>交易所提供的行情接口主要服务于市场参与者或信息服务商的接入系统。券商收到行情后，机房中可能有多个内部系统和多个 Colo 客户需要消费同一份数据。如果每台服务器都直接与交易所建立独立会话，会带来权限、连接数量、运维和恢复上的复杂性。</p><p>因此，券商通常会建设内部行情分发层：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>交易所行情接入</span></span>
<span class="line"><span>→ 券商内部接收与校验</span></span>
<span class="line"><span>→ 内部标准化或封装</span></span>
<span class="line"><span>→ A/B 分发节点</span></span>
<span class="line"><span>→ UDP 组播网络</span></span>
<span class="line"><span>→ 多台 Colo 服务器</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div><p>这个分发层解决的是“一份上游行情如何低延迟地送给很多接收者”，不等同于量化机构自己的行情处理程序。</p><h2 id="_2-券商可能发送什么数据" tabindex="-1">2. 券商可能发送什么数据 <a class="header-anchor" href="#_2-券商可能发送什么数据" aria-label="Permalink to &quot;2. 券商可能发送什么数据&quot;">​</a></h2><p>券商内部转发并不只有一种方式。量化机构必须先确认收到的究竟是哪一种。</p><h3 id="_2-1-交易所原始消息透传" tabindex="-1">2.1 交易所原始消息透传 <a class="header-anchor" href="#_2-1-交易所原始消息透传" aria-label="Permalink to &quot;2.1 交易所原始消息透传&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>券商传输包头</span></span>
<span class="line"><span>+ 交易所原始消息</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>特点：</p><ul><li>原始字段保留较完整；</li><li>量化机构需要自行适配不同交易所协议；</li><li>外层券商包序号和内层交易所业务序号必须区分；</li><li>协议升级需要量化机构同步适配。</li></ul><h3 id="_2-2-券商统一格式" tabindex="-1">2.2 券商统一格式 <a class="header-anchor" href="#_2-2-券商统一格式" aria-label="Permalink to &quot;2.2 券商统一格式&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>交易所协议</span></span>
<span class="line"><span>→ 券商标准化结构</span></span>
<span class="line"><span>→ 内部组播</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>特点：</p><ul><li>上交所、深交所等可以使用统一字段；</li><li>接入成本更低；</li><li>需要确认是否丢失交易所原始字段；</li><li>Channel、Seq、订单编号和时间戳可能被重写；</li><li>字段名称相同不代表语义与交易所原始字段相同。</li></ul><h3 id="_2-3-券商构建后输出盘口" tabindex="-1">2.3 券商构建后输出盘口 <a class="header-anchor" href="#_2-3-券商构建后输出盘口" aria-label="Permalink to &quot;2.3 券商构建后输出盘口&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>逐笔消息</span></span>
<span class="line"><span>→ 券商订单簿</span></span>
<span class="line"><span>→ 十档快照或盘口增量</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>特点：</p><ul><li>使用简单；</li><li>接收端不必自行维护全部逐笔状态；</li><li>无法还原被聚合掉的订单级信息；</li><li>本地模型依赖券商订单簿算法和恢复状态；</li><li>不适合需要订单编号、排队位置或精细订单流的策略。</li></ul><p>三种产品不能仅凭“都是 Level-2”混为一谈。</p><h2 id="_3-udp组播为什么适合机房行情分发" tabindex="-1">3. UDP组播为什么适合机房行情分发 <a class="header-anchor" href="#_3-udp组播为什么适合机房行情分发" aria-label="Permalink to &quot;3. UDP组播为什么适合机房行情分发&quot;">​</a></h2><p>UDP 组播允许发送节点向一个组播地址发送一份数据，由交换机复制到所有加入该组播组的端口。</p>`,23)),i(r,null,{default:l(()=>[(n(),t(p,null,{default:l(()=>[i(s,{id:"mermaid-134",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20P%5B%E5%88%B8%E5%95%86%E5%88%86%E5%8F%91%E8%8A%82%E7%82%B9%5D%20--%3E%20G%5BUDP%20%E7%BB%84%E6%92%AD%E7%BB%84%5D%0A%20%20%20%20G%20--%3E%20S1%5BColo%20%E6%9C%8D%E5%8A%A1%E5%99%A8%201%5D%0A%20%20%20%20G%20--%3E%20S2%5BColo%20%E6%9C%8D%E5%8A%A1%E5%99%A8%202%5D%0A%20%20%20%20G%20--%3E%20S3%5BColo%20%E6%9C%8D%E5%8A%A1%E5%99%A8%203%5D%0A%20%20%20%20G%20--%3E%20SN%5BColo%20%E6%9C%8D%E5%8A%A1%E5%99%A8%20N%5D%0A"})]),fallback:l(()=>[...a[1]||(a[1]=[e("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[7]||(a[7]=d(`<p>如果使用大量独立 TCP 连接，发送节点需要维护每个客户连接，并受到慢接收者、重传和发送缓存的影响。组播更适合高频行情的一对多分发：</p><ul><li>发送端只需发送一份；</li><li>交换网络完成复制；</li><li>某个接收者变慢不会直接阻塞其他接收者；</li><li>后续包不会因为一个包丢失而等待传输层重传。</li></ul><p>代价是 UDP 本身不保证：</p><ul><li>一定送达；</li><li>按顺序到达；</li><li>不重复；</li><li>自动重传；</li><li>接收者状态可见。</li></ul><p>因此，完整性检查和恢复必须由上层协议、双路网络或恢复服务完成。具体算法属于后续行情接收程序文章，本篇只讨论这些机制依赖的网络前提。</p><h2 id="_4-一个典型的券商udp包" tabindex="-1">4. 一个典型的券商UDP包 <a class="header-anchor" href="#_4-一个典型的券商udp包" aria-label="Permalink to &quot;4. 一个典型的券商UDP包&quot;">​</a></h2><p>券商内部 UDP 数据报可能包含外层传输头和一条或多条业务消息：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Ethernet Header</span></span>
<span class="line"><span>IP Header</span></span>
<span class="line"><span>UDP Header</span></span>
<span class="line"><span>Broker Packet Header</span></span>
<span class="line"><span>  source_id</span></span>
<span class="line"><span>  path_id</span></span>
<span class="line"><span>  packet_channel</span></span>
<span class="line"><span>  packet_sequence</span></span>
<span class="line"><span>  send_timestamp</span></span>
<span class="line"><span>  message_count</span></span>
<span class="line"><span>Market Message 1</span></span>
<span class="line"><span>Market Message 2</span></span>
<span class="line"><span>...</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br></div></div><p>需要特别区分：</p><ul><li><strong>外层 PacketSeq</strong>：描述券商发送的 UDP 包；</li><li><strong>内层业务 Channel/Seq</strong>：描述行情业务流中的消息顺序。</li></ul><p>一条 UDP 包可能包含多条业务消息；丢失一个 UDP 包，可能同时丢失多条业务记录。反过来，外层 PacketSeq 连续也不能证明内层业务消息一定完整，因为上游接入系统可能在封包前已经缺失数据。</p><h2 id="_5-a-b双路到底是什么" tabindex="-1">5. A/B双路到底是什么 <a class="header-anchor" href="#_5-a-b双路到底是什么" aria-label="Permalink to &quot;5. A/B双路到底是什么&quot;">​</a></h2><p>A/B 双路的目标通常包括：</p><ul><li>降低单链路故障影响；</li><li>一路丢包时从另一路获得同一业务消息；</li><li>选择先到的一路以降低尾部延迟；</li><li>监控两个路径的延迟和完整性差异。</li></ul><p>但是，“A/B”只是标签，不能自动证明两路真正独立。</p><h3 id="_5-1-四个不同概念" tabindex="-1">5.1 四个不同概念 <a class="header-anchor" href="#_5-1-四个不同概念" aria-label="Permalink to &quot;5.1 四个不同概念&quot;">​</a></h3><table tabindex="0"><thead><tr><th>概念</th><th>含义</th><th>能解决的问题</th></tr></thead><tbody><tr><td>双端口</td><td>一张网卡的两个物理端口</td><td>单根线缆或单端口问题</td></tr><tr><td>双网卡</td><td>一台服务器的两张网卡</td><td>单网卡、驱动或 PCIe 卡故障的一部分风险</td></tr><tr><td>双网络路径</td><td>不同交换机、线缆和端口</td><td>网络设备与物理链路故障</td></tr><tr><td>双行情源</td><td>独立上游接入节点或供应商</td><td>上游数据源和接入程序故障</td></tr></tbody></table><p>双网卡不等于双源，双交换机也不等于上游数据独立。</p><h3 id="_5-2-常见伪双路" tabindex="-1">5.2 常见伪双路 <a class="header-anchor" href="#_5-2-常见伪双路" aria-label="Permalink to &quot;5.2 常见伪双路&quot;">​</a></h3>`,19)),i(r,null,{default:l(()=>[(n(),t(p,null,{default:l(()=>[i(s,{id:"mermaid-319",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20U%5B%E5%8D%95%E4%B8%80%E4%B8%8A%E6%B8%B8%E6%8E%A5%E5%85%A5%E7%A8%8B%E5%BA%8F%5D%20--%3E%20D%5B%E5%8D%95%E4%B8%80%E5%88%86%E5%8F%91%E7%A8%8B%E5%BA%8F%5D%0A%20%20%20%20D%20--%3E%20SWA%5B%E4%BA%A4%E6%8D%A2%E6%9C%BA%20A%5D%0A%20%20%20%20D%20--%3E%20SWB%5B%E4%BA%A4%E6%8D%A2%E6%9C%BA%20B%5D%0A%20%20%20%20SWA%20--%3E%20NA%5B%E7%BD%91%E5%8D%A1%20A%5D%0A%20%20%20%20SWB%20--%3E%20NB%5B%E7%BD%91%E5%8D%A1%20B%5D%0A"})]),fallback:l(()=>[...a[2]||(a[2]=[e("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[8]||(a[8]=e("p",null,"这套结构可以防止部分交换机、线缆和网卡故障，但如果上游接入程序遗漏某条消息，A/B 会同时缺失。",-1)),a[9]||(a[9]=e("h3",{id:"_5-3-更完整的双路",tabindex:"-1"},[A("5.3 更完整的双路 "),e("a",{class:"header-anchor",href:"#_5-3-更完整的双路","aria-label":'Permalink to "5.3 更完整的双路"'},"​")],-1)),i(r,null,{default:l(()=>[(n(),t(p,null,{default:l(()=>[i(s,{id:"mermaid-326",class:"mermaid",graph:"flowchart%20LR%0A%20%20%20%20UA%5B%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20A%5D%20--%3E%20DA%5B%E5%88%86%E5%8F%91%E8%8A%82%E7%82%B9%20A%5D%20--%3E%20SWA%5B%E4%BA%A4%E6%8D%A2%E7%BD%91%E7%BB%9C%20A%5D%20--%3E%20NA%5B%E7%BD%91%E5%8D%A1%20A%5D%0A%20%20%20%20UB%5B%E6%8E%A5%E5%85%A5%E8%8A%82%E7%82%B9%20B%5D%20--%3E%20DB%5B%E5%88%86%E5%8F%91%E8%8A%82%E7%82%B9%20B%5D%20--%3E%20SWB%5B%E4%BA%A4%E6%8D%A2%E7%BD%91%E7%BB%9C%20B%5D%20--%3E%20NB%5B%E7%BD%91%E5%8D%A1%20B%5D%0A"})]),fallback:l(()=>[...a[3]||(a[3]=[e("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[10]||(a[10]=d(`<p>即使如此，仍需继续确认 UA 和 UB 是否共享交易所出口、运营商线路、时钟源、电源或机房设备。冗余设计的核心是识别共同故障域，而不是统计设备数量。</p><h2 id="_6-同源双路和异源多源" tabindex="-1">6. 同源双路和异源多源 <a class="header-anchor" href="#_6-同源双路和异源多源" aria-label="Permalink to &quot;6. 同源双路和异源多源&quot;">​</a></h2><h3 id="_6-1-同源双路" tabindex="-1">6.1 同源双路 <a class="header-anchor" href="#_6-1-同源双路" aria-label="Permalink to &quot;6.1 同源双路&quot;">​</a></h3><p>两路承载相同的逻辑业务事件，可能只是物理路径或发送节点不同。理想情况下，内层业务标识能够对应同一事件，但外层 UDP 包序号、封包数量和发送时间可以不同。</p><p>同源双路适合在接收程序前端做去重和互补，但前提是券商明确说明两路属于同一个业务序号域。</p><h3 id="_6-2-异源多源" tabindex="-1">6.2 异源多源 <a class="header-anchor" href="#_6-2-异源多源" aria-label="Permalink to &quot;6.2 异源多源&quot;">​</a></h3><p>例如：</p><ul><li>交易所直连源；</li><li>券商 A 的标准化源；</li><li>券商 B 的原始透传源；</li><li>第三方十档快照源。</li></ul><p>这些源的 Channel、Seq、封包方式和消息粒度通常不能直接比较。正确做法往往是独立接收、独立构建状态，再进行校验或整体切换，而不是把不同序号域的消息随意拼接。</p><p>本篇不展开多源订单簿合并，只强调：在网络设计阶段必须给每个源和路径建立明确身份，不能让接收程序只看到两个无法区分的 UDP Socket。</p><h2 id="_7-vlan和组播隔离" tabindex="-1">7. VLAN和组播隔离 <a class="header-anchor" href="#_7-vlan和组播隔离" aria-label="Permalink to &quot;7. VLAN和组播隔离&quot;">​</a></h2><p>VLAN 可以理解为交换网络中的逻辑隔离区域。券商可能按市场、行情产品、客户或 A/B 路划分 VLAN。</p><p>需要确认：</p><ul><li>A/B 是否属于不同 VLAN；</li><li>组播地址和 UDP 端口是否可能重复；</li><li>服务器接口是否加入正确 VLAN；</li><li>网络变更是否会把 A/B 接到同一广播域；</li><li>管理流量是否与行情流量共用网络。</li></ul><p>行情网络应尽量避免承载日志上传、数据库同步、部署、监控大流量等非关键业务。否则这些流量可能在交换机端口或服务器网卡前与行情争抢带宽和缓存。</p><h2 id="_8-igmp和组播转发表" tabindex="-1">8. IGMP和组播转发表 <a class="header-anchor" href="#_8-igmp和组播转发表" aria-label="Permalink to &quot;8. IGMP和组播转发表&quot;">​</a></h2><p>IGMP 是主机声明“我要接收某个组播组”的协议。交换机通过 IGMP Snooping 观察成员关系，只把组播数据发送到需要的端口。</p><h3 id="_8-1-正常过程" tabindex="-1">8.1 正常过程 <a class="header-anchor" href="#_8-1-正常过程" aria-label="Permalink to &quot;8.1 正常过程&quot;">​</a></h3><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>服务器加入组播组</span></span>
<span class="line"><span>→ 接入交换机学习成员关系</span></span>
<span class="line"><span>→ 组播转发表记录目标端口</span></span>
<span class="line"><span>→ 行情只复制到对应服务器</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_8-2-常见问题" tabindex="-1">8.2 常见问题 <a class="header-anchor" href="#_8-2-常见问题" aria-label="Permalink to &quot;8.2 常见问题&quot;">​</a></h3><ul><li>服务器没有成功加入组播；</li><li>IGMP Querier 配置异常；</li><li>成员关系超时；</li><li>交换机重启后未恢复转发表；</li><li>组播被泛洪到所有端口；</li><li>A/B 组播组配置反向；</li><li>源特定组播的源地址不匹配；</li><li>ACL 或安全策略阻断组播控制报文。</li></ul><h3 id="_8-3-解决方向" tabindex="-1">8.3 解决方向 <a class="header-anchor" href="#_8-3-解决方向" aria-label="Permalink to &quot;8.3 解决方向&quot;">​</a></h3><ul><li>固化组播地址、端口、源地址和 VLAN 清单；</li><li>盘前检查服务器成员关系；</li><li>检查交换机组播转发表；</li><li>监控组播加入和离开事件；</li><li>模拟交换机重启和接口抖动；</li><li>对网络配置变更执行前后消息连续性对比。</li></ul><h2 id="_9-交换机为什么会丢包" tabindex="-1">9. 交换机为什么会丢包 <a class="header-anchor" href="#_9-交换机为什么会丢包" aria-label="Permalink to &quot;9. 交换机为什么会丢包&quot;">​</a></h2><p>即使端口带宽显示远未占满，交换机仍可能因为微突发丢包。</p><h3 id="_9-1-什么是微突发" tabindex="-1">9.1 什么是微突发 <a class="header-anchor" href="#_9-1-什么是微突发" aria-label="Permalink to &quot;9.1 什么是微突发&quot;">​</a></h3><p>行情并不是均匀到达。开盘、收盘或价格快速变化时，大量委托、撤单和成交可能在极短时间内集中发布。</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>平均带宽不高</span></span>
<span class="line"><span>+ 瞬时大量小包到达</span></span>
<span class="line"><span>→ 出口队列短时间填满</span></span>
<span class="line"><span>→ 交换机缓存溢出</span></span>
<span class="line"><span>→ 部分包被丢弃</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>对行情网络，包速率 PPS 和瞬时队列占用经常比分钟平均带宽更重要。</p><h3 id="_9-2-交换机选型和配置关注点" tabindex="-1">9.2 交换机选型和配置关注点 <a class="header-anchor" href="#_9-2-交换机选型和配置关注点" aria-label="Permalink to &quot;9.2 交换机选型和配置关注点&quot;">​</a></h3><ul><li>小包转发性能；</li><li>端口和交换结构是否无阻塞；</li><li>出口缓冲和队列策略；</li><li>组播复制能力；</li><li>硬件时间戳和 PTP 支持；</li><li>端口丢弃、拥塞和错误计数；</li><li>配置变更和升级方式；</li><li>A/B 是否使用独立设备和独立上联。</li></ul><p>不应只根据交换机总背板带宽判断行情网络是否安全。</p><h2 id="_10-mtu和ip分片" tabindex="-1">10. MTU和IP分片 <a class="header-anchor" href="#_10-mtu和ip分片" aria-label="Permalink to &quot;10. MTU和IP分片&quot;">​</a></h2><p>MTU 表示链路允许承载的最大网络包尺寸。如果券商 UDP 数据报超过某段链路的 MTU，可能发生 IP 分片。</p><p>分片带来的风险：</p><ul><li>任意一个分片丢失，整个 UDP 数据报都无法恢复；</li><li>分片重组增加接收路径复杂度；</li><li>中间设备可能对分片处理不一致；</li><li>抓包和故障定位更加困难。</li></ul><p>需要统一确认：</p><ul><li>发送节点 MTU；</li><li>所有交换端口和 VLAN 的 MTU；</li><li>服务器网卡 MTU；</li><li>最大 UDP 数据报长度；</li><li>是否允许 Jumbo Frame；</li><li>是否明确禁止 IP 分片。</li></ul><p>低延迟系统不应默认“大 MTU 一定更快”或“小包一定不会分片”，而应以实际封包大小和全链路一致配置为准。</p><h2 id="_11-光纤、光模块和线缆" tabindex="-1">11. 光纤、光模块和线缆 <a class="header-anchor" href="#_11-光纤、光模块和线缆" aria-label="Permalink to &quot;11. 光纤、光模块和线缆&quot;">​</a></h2><p>行情进入服务器前的最后一段仍然是物理链路。常见连接介质包括光纤、DAC 和 AOC。</p><h3 id="_11-1-需要匹配的因素" tabindex="-1">11.1 需要匹配的因素 <a class="header-anchor" href="#_11-1-需要匹配的因素" aria-label="Permalink to &quot;11.1 需要匹配的因素&quot;">​</a></h3><ul><li>端口速率；</li><li>SFP、SFP28、SFP56、QSFP 等接口形态；</li><li>单模或多模；</li><li>波长和传输距离；</li><li>交换机与网卡兼容性；</li><li>厂商固件对白名单的要求；</li><li>FEC 等链路参数。</li></ul><h3 id="_11-2-常见故障" tabindex="-1">11.2 常见故障 <a class="header-anchor" href="#_11-2-常见故障" aria-label="Permalink to &quot;11.2 常见故障&quot;">​</a></h3><ul><li>光功率异常；</li><li>接头污染或松动；</li><li>光纤弯折；</li><li>模块温度过高；</li><li>CRC 或帧错误；</li><li>链路频繁上下线；</li><li>端口协商到错误速率；</li><li>A/B 两路经过同一桥架或配线设备。</li></ul><h3 id="_11-3-运维措施" tabindex="-1">11.3 运维措施 <a class="header-anchor" href="#_11-3-运维措施" aria-label="Permalink to &quot;11.3 运维措施&quot;">​</a></h3><ul><li>建立经过验证的模块和线缆清单；</li><li>监控光功率、温度和误码；</li><li>保存端口上下线事件；</li><li>A/B 使用独立端口、模块、线缆和路径；</li><li>准备已验证的冷备件；</li><li>网络变更后执行原始包数量与延迟对比。</li></ul><h2 id="_12-行情到达服务器网卡时发生了什么" tabindex="-1">12. 行情到达服务器网卡时发生了什么 <a class="header-anchor" href="#_12-行情到达服务器网卡时发生了什么" aria-label="Permalink to &quot;12. 行情到达服务器网卡时发生了什么&quot;">​</a></h2><p>到达本文终点时，链路发生的是：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>交换机发出以太网帧</span></span>
<span class="line"><span>→ 光模块或线缆传输</span></span>
<span class="line"><span>→ 网卡物理层接收信号</span></span>
<span class="line"><span>→ 网卡完成基础帧校验</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><p>此时行情还没有：</p><ul><li>被应用程序读取；</li><li>被解析成委托或成交；</li><li>被按 Channel 和 Seq 排序；</li><li>被 A/B 合并；</li><li>被用于构建订单簿。</li></ul><p>因此，“交换机端口显示已发送”和“行情程序已经收到”之间仍然隔着网卡、PCIe、内存、驱动、接收队列和软件路径。这些内容会在后续文章讨论。</p><h2 id="_13-服务器前的故障如何定位" tabindex="-1">13. 服务器前的故障如何定位 <a class="header-anchor" href="#_13-服务器前的故障如何定位" aria-label="Permalink to &quot;13. 服务器前的故障如何定位&quot;">​</a></h2><p>假设行情程序最终报告业务序号缺口，排查不能直接从程序代码开始。</p>`,55)),i(r,null,{default:l(()=>[(n(),t(p,null,{default:l(()=>[i(s,{id:"mermaid-810",class:"mermaid",graph:"flowchart%20TD%0A%20%20%20%20G%5B%E5%8F%91%E7%8E%B0%E4%B8%9A%E5%8A%A1%E6%B6%88%E6%81%AF%E7%BC%BA%E5%8F%A3%5D%20--%3E%20A%7BA%E8%B7%AF%E6%98%AF%E5%90%A6%E7%BC%BA%E5%A4%B1%7D%0A%20%20%20%20G%20--%3E%20B%7BB%E8%B7%AF%E6%98%AF%E5%90%A6%E7%BC%BA%E5%A4%B1%7D%0A%20%20%20%20A%20--%3E%20PA%5B%E6%A3%80%E6%9F%A5A%E8%B7%AF%E5%8E%9F%E5%A7%8BUDP%E5%8C%85%E4%B8%8EPacketSeq%5D%0A%20%20%20%20B%20--%3E%20PB%5B%E6%A3%80%E6%9F%A5B%E8%B7%AF%E5%8E%9F%E5%A7%8BUDP%E5%8C%85%E4%B8%8EPacketSeq%5D%0A%20%20%20%20PA%20--%3E%20SA%5B%E6%A3%80%E6%9F%A5%E4%BA%A4%E6%8D%A2%E6%9C%BAA%E5%87%BA%E5%8F%A3%E8%AE%A1%E6%95%B0%5D%0A%20%20%20%20PB%20--%3E%20SB%5B%E6%A3%80%E6%9F%A5%E4%BA%A4%E6%8D%A2%E6%9C%BAB%E5%87%BA%E5%8F%A3%E8%AE%A1%E6%95%B0%5D%0A%20%20%20%20SA%20--%3E%20DA%5B%E6%A3%80%E6%9F%A5%E5%88%86%E5%8F%91%E8%8A%82%E7%82%B9A%E6%98%AF%E5%90%A6%E5%8F%91%E9%80%81%5D%0A%20%20%20%20SB%20--%3E%20DB%5B%E6%A3%80%E6%9F%A5%E5%88%86%E5%8F%91%E8%8A%82%E7%82%B9B%E6%98%AF%E5%90%A6%E5%8F%91%E9%80%81%5D%0A%20%20%20%20DA%20--%3E%20U%5B%E6%A3%80%E6%9F%A5%E5%88%B8%E5%95%86%E4%B8%8A%E6%B8%B8%E6%8E%A5%E5%85%A5%E6%95%B0%E6%8D%AE%5D%0A%20%20%20%20DB%20--%3E%20U%0A"})]),fallback:l(()=>[...a[4]||(a[4]=[e("div",{class:"mermaid mermaid--loading","aria-busy":"true","aria-label":"Loading diagram"},null,-1)])]),_:1}))]),_:1}),a[11]||(a[11]=d('<h3 id="_13-1-只有a路缺失" tabindex="-1">13.1 只有A路缺失 <a class="header-anchor" href="#_13-1-只有a路缺失" aria-label="Permalink to &quot;13.1 只有A路缺失&quot;">​</a></h3><p>优先关注：</p><ul><li>分发节点 A；</li><li>交换网络 A；</li><li>A 路组播配置；</li><li>A 路光链路；</li><li>网卡 A 前的物理端口。</li></ul><h3 id="_13-2-a-b同时缺失相同业务消息" tabindex="-1">13.2 A/B同时缺失相同业务消息 <a class="header-anchor" href="#_13-2-a-b同时缺失相同业务消息" aria-label="Permalink to &quot;13.2 A/B同时缺失相同业务消息&quot;">​</a></h3><p>优先关注：</p><ul><li>两路共同上游；</li><li>内部标准化或封装程序；</li><li>共享行情总线；</li><li>交易所到券商的接入链路；</li><li>两路是否其实属于同一个数据副本。</li></ul><h3 id="_13-3-外层udp包连续但业务消息缺失" tabindex="-1">13.3 外层UDP包连续但业务消息缺失 <a class="header-anchor" href="#_13-3-外层udp包连续但业务消息缺失" aria-label="Permalink to &quot;13.3 外层UDP包连续但业务消息缺失&quot;">​</a></h3><p>说明问题可能发生在 UDP 封包之前，或供应商对消息做了过滤、转换和重新编号。不能只监控 PacketSeq 而忽略业务层身份。</p><h2 id="_14-全链路监控指标" tabindex="-1">14. 全链路监控指标 <a class="header-anchor" href="#_14-全链路监控指标" aria-label="Permalink to &quot;14. 全链路监控指标&quot;">​</a></h2><h3 id="_14-1-分发节点" tabindex="-1">14.1 分发节点 <a class="header-anchor" href="#_14-1-分发节点" aria-label="Permalink to &quot;14.1 分发节点&quot;">​</a></h3><ul><li>每个行情产品的输入和输出消息数；</li><li>每秒包数和字节数；</li><li>封包等待时间；</li><li>发送队列深度；</li><li>PacketSeq；</li><li>A/B 输出差异；</li><li>进程 CPU 和内存压力。</li></ul><h3 id="_14-2-交换网络" tabindex="-1">14.2 交换网络 <a class="header-anchor" href="#_14-2-交换网络" aria-label="Permalink to &quot;14.2 交换网络&quot;">​</a></h3><ul><li>入口和出口包数；</li><li>端口丢弃；</li><li>队列拥塞；</li><li>CRC 和帧错误；</li><li>组播成员数量；</li><li>链路上下线；</li><li>PTP 状态；</li><li>峰值 PPS。</li></ul><h3 id="_14-3-物理链路" tabindex="-1">14.3 物理链路 <a class="header-anchor" href="#_14-3-物理链路" aria-label="Permalink to &quot;14.3 物理链路&quot;">​</a></h3><ul><li>光功率；</li><li>模块温度；</li><li>FEC 或误码计数；</li><li>端口速率；</li><li>模块和线缆序列号；</li><li>变更时间和操作记录。</li></ul><h3 id="_14-4-a-b比较" tabindex="-1">14.4 A/B比较 <a class="header-anchor" href="#_14-4-a-b比较" aria-label="Permalink to &quot;14.4 A/B比较&quot;">​</a></h3><ul><li>两路包数差异；</li><li>两路到达延迟差；</li><li>单路静默时间；</li><li>同一业务事件的字段差异；</li><li>两路共同缺口；</li><li>两路同时发生链路错误的频率。</li></ul><h2 id="_15-盘前、盘中和盘后流程" tabindex="-1">15. 盘前、盘中和盘后流程 <a class="header-anchor" href="#_15-盘前、盘中和盘后流程" aria-label="Permalink to &quot;15. 盘前、盘中和盘后流程&quot;">​</a></h2><h3 id="_15-1-盘前" tabindex="-1">15.1 盘前 <a class="header-anchor" href="#_15-1-盘前" aria-label="Permalink to &quot;15.1 盘前&quot;">​</a></h3><ol><li>检查分发节点 A/B；</li><li>检查组播地址、端口、源地址和 VLAN；</li><li>检查 IGMP 成员关系；</li><li>检查交换机端口和光链路；</li><li>检查服务器两张网卡端口状态；</li><li>比较 A/B 测试消息；</li><li>检查时间同步；</li><li>确认原始包录制和监控已经启动。</li></ol><h3 id="_15-2-盘中" tabindex="-1">15.2 盘中 <a class="header-anchor" href="#_15-2-盘中" aria-label="Permalink to &quot;15.2 盘中&quot;">​</a></h3><ul><li>单路断流时继续观察备用路并告警；</li><li>两路同时异常时将行情源标记为不可用；</li><li>交换机丢包或光链路误码时快速定位端口；</li><li>配置变更必须审计；</li><li>不以“还有 UDP 包到达”代替业务完整性判断。</li></ul><h3 id="_15-3-盘后" tabindex="-1">15.3 盘后 <a class="header-anchor" href="#_15-3-盘后" aria-label="Permalink to &quot;15.3 盘后&quot;">​</a></h3><ul><li>统计 A/B 包数、缺口、重复和延迟；</li><li>对比交换机与服务器端计数；</li><li>复盘所有端口错误和链路抖动；</li><li>保存网络配置快照；</li><li>对异常时间段进行原始包重放；</li><li>更新故障域和依赖关系图。</li></ul><h2 id="_16-故障注入计划" tabindex="-1">16. 故障注入计划 <a class="header-anchor" href="#_16-故障注入计划" aria-label="Permalink to &quot;16. 故障注入计划&quot;">​</a></h2><p>生产前至少应验证：</p><ul><li>断开 A 路物理链路；</li><li>断开 B 路物理链路；</li><li>重启一台接入交换机；</li><li>清除组播成员关系；</li><li>模拟端口微突发；</li><li>模拟单路丢包、重复和延迟；</li><li>模拟两路到达顺序反转；</li><li>模拟分发节点停止发送；</li><li>模拟 A/B 同时缺少同一业务消息；</li><li>验证每种故障能否被正确归因和告警。</li></ul><p>故障注入的目的不是证明系统“永远不出错”，而是确认：发生错误时，系统知道影响了哪条路径、哪些行情产品和哪些服务器。</p><h2 id="_17-关键设计取舍" tabindex="-1">17. 关键设计取舍 <a class="header-anchor" href="#_17-关键设计取舍" aria-label="Permalink to &quot;17. 关键设计取舍&quot;">​</a></h2><h3 id="_17-1-一张双口卡还是两张独立卡" tabindex="-1">17.1 一张双口卡还是两张独立卡 <a class="header-anchor" href="#_17-1-一张双口卡还是两张独立卡" aria-label="Permalink to &quot;17.1 一张双口卡还是两张独立卡&quot;">​</a></h3><p>一张双口卡成本更低、布线简单，但两个端口共享网卡芯片、PCIe 插槽、固件和供电。若目标是降低单卡故障风险，A/B 应优先使用两张独立物理卡。</p><h3 id="_17-2-双路抢先还是严格主备" tabindex="-1">17.2 双路抢先还是严格主备 <a class="header-anchor" href="#_17-2-双路抢先还是严格主备" aria-label="Permalink to &quot;17.2 双路抢先还是严格主备&quot;">​</a></h3><p>双路抢先可以降低到达延迟并利用另一条路补齐单路丢包，但接收侧合并逻辑更复杂。严格主备实现简单，却不能同时利用两条路的低延迟优势。该选择属于网卡之后的行情接收程序设计，本文只要求网络层保留可靠的路径标识和独立性。</p><h3 id="_17-3-共享网络还是专用行情网络" tabindex="-1">17.3 共享网络还是专用行情网络 <a class="header-anchor" href="#_17-3-共享网络还是专用行情网络" aria-label="Permalink to &quot;17.3 共享网络还是专用行情网络&quot;">​</a></h3><p>共享网络利用率高，但非行情流量可能产生拥塞和微突发。高频场景通常更倾向专用 VLAN、专用交换端口甚至独立交换网络，用资源换取更稳定的延迟和故障边界。</p><h2 id="_18-仍需向券商确认的问题" tabindex="-1">18. 仍需向券商确认的问题 <a class="header-anchor" href="#_18-仍需向券商确认的问题" aria-label="Permalink to &quot;18. 仍需向券商确认的问题&quot;">​</a></h2><ul><li>券商输出的是原始透传、统一格式还是盘口结果；</li><li>外层 PacketSeq 和内层业务 Seq 分别如何定义；</li><li>A/B 是否属于同一个业务序号域；</li><li>A/B 分发节点是否共享上游接入程序；</li><li>是否提供独立恢复服务；</li><li>每个 UDP 包最多包含多少业务消息；</li><li>最大包长和 MTU 要求；</li><li>组播地址、端口、源地址和 VLAN；</li><li>交换机和物理路径是否真正独立；</li><li>PTP 时间由谁提供；</li><li>Colo 客户能否获得交换机端口和分发节点指标。</li></ul><p>这些信息在没有正式接口规范和机房拓扑前都属于“未确认”。</p><h2 id="_19-下一篇-服务器网卡怎么选" tabindex="-1">19. 下一篇：服务器网卡怎么选 <a class="header-anchor" href="#_19-下一篇-服务器网卡怎么选" aria-label="Permalink to &quot;19. 下一篇：服务器网卡怎么选&quot;">​</a></h2><p>下一篇将把终点放在服务器硬件入口，讨论：</p><ul><li>Solarflare、NVIDIA ConnectX 和 FPGA 定制卡的定位差异；</li><li>端口速率、PPS、尾部延迟和硬件时间戳；</li><li>两张独立网卡与一张双口网卡的取舍；</li><li>PCIe、NUMA 和固件版本为什么需要纳入选型；</li><li>为什么 FPGA 不是简单的高配网卡；</li><li>如何设计可复现的网卡验收测试。</li></ul><blockquote><p>本文仅为个人学习笔记和系统架构设计整理，不构成任何投资建议或交易建议。高频量化交易系统涉及市场风险、技术风险、合规风险和运维风险，任何实盘部署都应经过充分测试、独立验证和风险评估。</p></blockquote>',42))])}const k=u(E,[["render",c]]);export{q as __pageData,k as default};
